#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int64_t sum=0, ans=0;
        for(int i=1;i<=N;++i){
            int64_t x; scanf("%lld",&x);
            sum+=x;
            int64_t cur=(sum + i - 1)/i; // ceil division
            if(cur>ans) ans=cur;
        }
        printf("%lld\n",ans);
    }
    return 0;
}

